import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class XPathToUISelector {

    public static String convertXPathToUISelector(String xpath) {
        if (xpath == null || xpath.isEmpty()) {
            return "";
        }

        // Simple XPath to UI selector conversion (expand as needed)
        xpath = xpath.trim();

        // ID selector
        if (xpath.matches("//div[@id='(.*)']")) {
            String id = Pattern.compile("@id='(.*)'").matcher(xpath).group(1).trim();
            return "#" + id;
        }

        // Class selector
        if (xpath.matches("//div[@class='(.*)']")) {
            String class_name = Pattern.compile("@class='(.*)'").matcher(xpath).group(1).trim();
            return "." + class_name;
        }

        // Text selector
        if (xpath.matches("//a[text()='(.*)']")) {
            String text = Pattern.compile("text()='(.*)'").matcher(xpath).group(1).trim();
            return "text()='" + text + "'";
        }

        // Child selector
        if (xpath.matches("//div[@id='(.*)']/p")) {
            String id = Pattern.compile("@id='(.*)'").matcher(xpath).group(1).trim();
            return "#" + id + " > p";
        }

        // More complex logic can be added here to handle other XPath patterns

        return "Unsupported XPath: " + xpath;
    }

    public static void main(String[] args) {
