        String uiSelector1 = convertXPathToUISelector(xpath1);
        System.out.println("XPath: " + xpath1 + ", UI Selector: " + uiSelector1);

        String xpath2 = "//div[@class='myClass']";
        String uiSelector2 = convertXPathToUISelector(xpath2);
        System.out.println("XPath: " + xpath2 + ", UI Selector: " + uiSelector2);

        String xpath3 = "//a[text()='Click Here']";
        String uiSelector3 = convertXPathToUISelector(xpath3);
        System.out.println("XPath: " + xpath3 + ", UI Selector: " + uiSelector3);

        String xpath4 = "//div[@id='myDiv']/p";
        String uiSelector4 = convertXPathToUISelector(xpath4);
